do
    local Players = game:GetService("Players")
    local UIS = game:GetService("UserInputService")

    local lp = Players.LocalPlayer

    local function getChar()
        return lp.Character or lp.CharacterAdded:Wait()
    end

    local function getHRP()
        local char = getChar()
        return char:WaitForChild("HumanoidRootPart")
    end

    -- глобальные переменные, чтобы не конфликтовать с чужим кодом
    getgenv().SAB_InstantSteal_Enabled = true          -- сразу включён
    getgenv().SAB_InstantSteal_BaseCF  = getgenv().SAB_InstantSteal_BaseCF or nil

    -- сохранить позицию базы (нажимаешь H, стоя на зелёной зоне)
    local function saveBase()
        local hrp = getHRP()
        getgenv().SAB_InstantSteal_BaseCF = hrp.CFrame
        print("[HidenHub] Base position saved.")
    end

    -- телепорт на базу (нажимаешь G с брэинротом в руках)
    local function instantSteal()
        if not getgenv().SAB_InstantSteal_Enabled then return end
        local baseCF = getgenv().SAB_InstantSteal_BaseCF
        if not baseCF then
            warn("[HidenHub] Base not saved. Press H on the green zone first.")
            return
        end
        local hrp = getHRP()
        hrp.CFrame = baseCF
    end

    UIS.InputBegan:Connect(function(input, gpe)
        if gpe then return end

        if input.KeyCode == Enum.KeyCode.H then
            -- сохранить текущую позицию как зону сбора
            saveBase()
        elseif input.KeyCode == Enum.KeyCode.G then
            -- тп на сохранённую базу
            instantSteal()
        end
    end)

    print("[HidenHub] Instant Steal hotkeys loaded: H = save base, G = TP.")
end
